import React from 'react';
import PropTypes from 'prop-types';
import FeedbackCaution24 from '@andes/icons/FeedbackCaution24';
import FeedbackInfo24 from '@andes/icons/FeedbackInfo24';
import FeedbackNegative24 from '@andes/icons/FeedbackNegative24';
import FeedbackPositive24 from '@andes/icons/FeedbackPositive24';
import { VisuallyHidden } from '@andes/visually-hidden';
import { useId } from '@andes/context';
import { DEPRECATED_BADGE_COLORS, namespace } from './constants';
import computeColorProps from './utils/computeColorProps';
import classNames from 'classnames';
import { useThemeContext } from '@andes/themes';
import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';
import { WARNING_COLORS } from './constants/warnings';

/**
 * @param {'accent' | 'green' | 'orange' | 'red'} color
 */
const getSign = (color) => {
  const commonProps = { className: `${namespace}__icon-inner`, color: 'currentColor' };

  const colors = {
    accent: <FeedbackInfo24 {...commonProps} key="badge-info" />,
    green: <FeedbackPositive24 {...commonProps} key="badge-success" />,
    orange: <FeedbackCaution24 {...commonProps} key="badge-warning" />,
    red: <FeedbackNegative24 {...commonProps} key="badge-error" />,
  };

  return colors[color];
};

/** @type {typeof import('..').PillIcon} */
const PillIcon = (props) => {
  const {
    className,
    color,
    id,
    size = 'large',
    srLabel,
    ref,
    backgroundType,
    customVariant,
    ...otherProps
  } = props;

  const allProps = { customVariant, size, ...props };

  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  // @deprecate [color] options: ['accent', 'gray', 'green', 'orange', 'red'] - Warning from: 9.0.0
  if (typeof color === 'string') {
    warning(!includes(DEPRECATED_BADGE_COLORS, color), WARNING_COLORS);
  }

  const computedColor = computeColorProps({ color });

  const andesDataAttributes = {
    'data-andes-badge': true,
    'data-andes-badge-type': 'icon',
    'data-andes-badge-size': size,
    ...themeHash,
  };

  const classes = classNames(namespace, `${namespace}--pill`, `${namespace}--${computedColor}`, className, `${namespace}--pill-icon`, {
    [`${namespace}--${size}`]: size,
    [`${namespace}--color-on-background`]: backgroundType === 'complexBackground', // only allowed for loud hierarchy
  }, getThemedComponentClasses?.('badge', allProps));

  return (
    <div
      className={classes}
      id={componentId}
      ref={ref}
      {...otherProps}
      {...andesDataAttributes}
    >
      {srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>}
      <div aria-hidden="true" className={`${namespace}__icon`}>
        {getSign(
          // @ts-expect-error: PillIcon does not accept gray nor inverted
          computedColor,
        )}
      </div>
    </div>
  );
};

PillIcon.propTypes = {
  className: PropTypes.string,
  color: PropTypes.oneOf([
    'caution',
    'informative',
    'inverted',
    'negative',
    'neutral',
    'positive',
  ]),
  customVariant: PropTypes.string,
  id: PropTypes.string,
  size: PropTypes.oneOf(['xsmall', 'small', 'large']),
  srLabel: PropTypes.string,
  backgroundType: PropTypes.oneOf(['basic', 'complexBackground']),
};

PillIcon.displayName = 'PillIcon';

export default PillIcon;
