import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { VisuallyHidden } from '@andes/visually-hidden';
import { useId } from '@andes/context';
import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';
import { DEPRECATED_BADGE_COLORS, namespace } from './constants';
import { WARNING_COLORS } from './constants/warnings';
import computeColorProps from './utils/computeColorProps';
import { useThemeContext } from '@andes/themes';

/**
 * Badges are used to indicate an status or to differentiate an element, block or content from others.
 */

/** @type {typeof import('../index').Dot} */
const Dot = (props) => {
  const {
    className,
    color,
    id,
    srLabel,
    ref,
    backgroundType,
    customVariant,
    ...otherProps
  } = props;

  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  // @deprecate [color] options: ['accent', 'gray', 'green', 'orange', 'red'] - Warning from: 9.0.0
  if (typeof color === 'string') {
    warning(!includes(DEPRECATED_BADGE_COLORS, color), WARNING_COLORS);
  }

  const computedColor = computeColorProps({ color });

  const classes = classNames(
    namespace,
    className,
    `${namespace}--dot`,
    `${namespace}--${computedColor}`,
    {
      [`${namespace}--color-on-background`]:
        backgroundType === 'complexBackground',
    },
    getThemedComponentClasses?.('badge', props),
  );

  const sharedProps = {
    className: classes,
    id: componentId,
    ref,
    ...otherProps,
    'data-andes-badge': true,
    'data-andes-badge-type': 'dot',
    ...themeHash,
  };

  return (
    <div {...sharedProps}>
      {srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>}
    </div>
  );
};

Dot.displayName = 'Dot';

Dot.propTypes = {
  className: PropTypes.string,
  color: PropTypes.oneOf([
    'caution',
    'informative',
    'inverted',
    'negative',
    'neutral',
    'positive',
  ]),
  customVariant: PropTypes.string,
  id: PropTypes.string,
  srLabel: PropTypes.string,
  backgroundType: PropTypes.oneOf(['basic', 'complexBackground']),
};

export default Dot;
