// This function attempts to keep backwards compatibility with old colors

/** @typedef {import('../..').DeprecatedBadgeColors} DeprecatedBadgeColors */
/** @typedef {import('../..').BadgeColors} BadgeColors */

/**
 * @typedef {Object} Props
 * @prop {DeprecatedBadgeColors | BadgeColors} [color]
 */

/** @type {(props:Props) => DeprecatedBadgeColors | 'inverted'} */
const computeColorProps = ({ color }) => {
  // @deprecate [color] options: ['accent', 'gray', 'green', 'orange', 'red'] - Warning from: 9.0.0
  switch (color) {
    case 'informative':
      return 'accent';
    case 'neutral':
      return 'gray';
    case 'caution':
      return 'orange';
    case 'negative':
      return 'red';
    case 'positive':
      return 'green';
    default:
      return color || 'accent';
  }
};

export default computeColorProps;
